// 1. Ukládání příchozích dat do kontextu paměti Node-RED
// Zajišťujeme tak retenci stavů i při asynchronním toku zpráv.
if (msg.topic.includes("/Dc/0/Current")) flow.set("actualI", msg.payload);
if (msg.topic.includes("/Info/MaxChargeCurrent")) flow.set("limitI", msg.payload);
if (msg.topic.includes("/Info/MaxChargeVoltage")) flow.set("maxCVL", msg.payload);

// 2. Kontrola, zda máme všechna data. Spouštíme výpočet jen při aktualizaci proudu.
if (!msg.topic.includes("/Dc/0/Current")) return null;

// Načtení hodnot s defaulty pro jistotu
let actualI = flow.get("actualI") || 0;
let limitI = flow.get("limitI") || null;
let maxCVL = flow.get("maxCVL") || null;

// Ochrana, pokud BMS ztratí signál - nic neděláme
if (limitI === null || maxCVL === null) return null;

// Načtení minulé hodnoty CVL (naše paměť) nebo nastavení na výchozí hodnotu BMS
let currentTargetV = flow.get("currentTargetV") || maxCVL;

// 3. Konfigurace regulace (Parametry)
const stepDown = 0.05;    // V: Jak moc snížit při přetížení
const stepUp = 0.02;      // V: Jak pomalu se vracet, když je bezpečno
const bufferA = 5;        // A: Bezpečnostní mez pod limitem před uvolněním brzdy
const minSafeV = 52.0;    // V: Nikdy nepustit pod tuto hranici (aby se nezačalo vybíjet)

let actionReason = "None";

// --- HLAVNÍ LOGIKA ---
if (actualI > limitI) {
    currentTargetV -= stepDown;
    actionReason = "Snižování (překročen limit)";
} else if (actualI < (limitI - bufferA)) {
    // Pokud jsme pod limitem s rezervou a napětí je aktuálně uškrcené
    if (currentTargetV < maxCVL) {
        currentTargetV += stepUp;
        actionReason = "Uvolňování (jsme pod limitem s rezervou)";
    }
}

// --- BEZPEČNOSTNÍ POJISTKY ---
// Ochrana shora - nedovolíme víc než BMS
if (currentTargetV > maxCVL) currentTargetV = maxCVL;
// Ochrana zdola - nepustíme napětí k nule
if (currentTargetV < minSafeV) currentTargetV = minSafeV;

// Uložíme nový stav
flow.set("currentTargetV", currentTargetV);

// Formátování a příprava výstupu
currentTargetV = Math.round(currentTargetV * 100) / 100;

// Minimalizace zápisové bouře - zapisujeme, jen pokud je hodnota nová nebo uplynul čas.
let lastSentV = flow.get("lastSentV") || 0;
if (currentTargetV !== lastSentV) {
    flow.set("lastSentV", currentTargetV);
    msg.payload = currentTargetV;

    // Vytvoříme jednoduchý log výstup pro Node-RED Debug
    node.warn(`Akce: ${actionReason} | Proud: ${actualI.toFixed(1)}A (Limit: ${limitI}A) | BMS maxCVL: ${maxCVL}V | Nové CVL: ${currentTargetV}V`);

    return msg;
} else {
    return null; // Hodnota se nezměnila, není důvod budit Venus OS sběrnici.
}
